import React, { useContext, useEffect, useState } from 'react';
import { AuthContext } from '../contexts/AuthContext';
import { io } from 'socket.io-client';
import ChessBoard from '../components/ChessBoard';

const API_URL = 'http://localhost:3001';
let socket;

export default function RoomPage({ roomId }) {
  const { user } = useContext(AuthContext);
  const [room, setRoom] = useState(null);
  const [match, setMatch] = useState(null);
  const [fen, setFen] = useState('rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1');
  const [status, setStatus] = useState('Waiting for room');
  const [messages, setMessages] = useState([]);
  const [gameStatus, setGameStatus] = useState('waiting');
  const [whitePlayer, setWhitePlayer] = useState(null);
  const [blackPlayer, setBlackPlayer] = useState(null);
  const [currentPlayerColor, setCurrentPlayerColor] = useState(null);
  const [boardOrientation, setBoardOrientation] = useState('white');

  useEffect(() => {
    if (!roomId) return;
    socket = io(API_URL);
    socket.emit('identify', { userId: user.id });
    socket.emit('joinRoom', { roomId, userId: user.id });

    socket.on('roomUpdate', (r) => { 
      setRoom(r); 
      setStatus('Room updated'); 
    });

    socket.on('matchStarted', (data) => {
      if (data.roomId === roomId) {
        setMatch(data);
        setFen(data.fen || 'rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1');
        
        // Set player info
        if (data.whitePlayerId === user.id) {
          setCurrentPlayerColor('white');
          setBoardOrientation('white');
        } else if (data.blackPlayerId === user.id) {
          setCurrentPlayerColor('black');
          setBoardOrientation('black');
        } else {
          setCurrentPlayerColor(null); // Spectator
        }
        
        setWhitePlayer(data.whitePlayer || { id: data.whitePlayerId, username: 'White Player' });
        setBlackPlayer(data.blackPlayer || { id: data.blackPlayerId, username: 'Black Player' });
        
        setGameStatus('playing');
        setStatus('Match started - ' + (currentPlayerColor ? `You are ${currentPlayerColor}` : 'You are spectating'));
        setMessages(prev => [...prev, { type: 'system', text: '🎮 Match has started!' }]);
      }
    });

    socket.on('moveMade', ({ matchId, fen: newFen, move }) => {
      if (match?.matchId === matchId) {
        setFen(newFen);
        if (move?.san) {
          setMessages(prev => [...prev, { type: 'move', text: `Move: ${move.san}` }]);
        }
      }
    });

    socket.on('matchEnded', (data) => {
      if (match?.matchId === data.matchId) {
        setGameStatus(data.result || 'finished');
        setStatus(`Match ended. Winner: ${data.winner}`);
        setMessages(prev => [...prev, { type: 'result', text: `✓ Match ended. Winner: ${data.winner}` }]);
      }
    });

    socket.on('roomCompleted', (data) => {
      setStatus('Room completed');
      setRoom(data);
      setGameStatus('completed');
      setMessages(prev => [...prev, { type: 'system', text: '🏆 Room is now completed!' }]);
    });

    socket.on('invalidMove', (data) => {
      setMessages(prev => [...prev, { type: 'error', text: `Invalid move: ${data.reason}` }]);
    });

    return () => {
      socket.disconnect();
    };
  }, [roomId, user.id]);

  const handleMove = ({ from, to, promotion, san }) => {
    if (!match) return;
    if (!currentPlayerColor) return; // Spectator cannot move
    
    socket.emit('makeMove', { 
      roomId, 
      matchId: match.matchId, 
      from, 
      to, 
      promotion,
      san 
    });
  };

  const isSpectator = currentPlayerColor === null && match !== null;
  const currentPlayer = currentPlayerColor === 'white' ? whitePlayer : (currentPlayerColor === 'black' ? blackPlayer : null);

  if (!roomId) {
    return (
      <div className="min-h-screen flex items-center justify-center px-4">
        <div className="card text-center max-w-md">
          <h2 className="text-2xl font-bold mb-4">No Room Selected</h2>
          <p className="text-slate-400 mb-6">Please join from lobby to start a match.</p>
          <a href="/" className="btn-primary inline-block">Back to Lobby</a>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen px-4 py-8 bg-[linear-gradient(135deg,#0f172a_0%,#020617_80%)]">
      <div className="max-w-6xl mx-auto">        {/* Header */}
        <div className="flex flex-wrap items-center justify-between gap-4 mb-8">
          <div>
            <h1 className="text-4xl font-bold mb-2">{roomId}</h1>
            <p className={`text-sm font-semibold ${
              match ? 'text-green-300' : 'text-yellow-300'
            }`}>
              {status}
            </p>
          </div>
          <a href="/" className="btn-secondary">Leave Room</a>
        </div>

        <div className="grid lg:grid-cols-4 gap-6">          {/* Chess Board */}
          <div className="lg:col-span-3">
            <div className="card">
              <div className="bg-slate-900 rounded-lg p-4 flex justify-center min-h-96">
                {match ? (
                  <ChessBoard 
                    roomId={roomId}
                    fen={fen}
                    onMove={handleMove}
                    currentPlayer={currentPlayer}
                    whitePlayer={whitePlayer}
                    blackPlayer={blackPlayer}
                    isSpectator={isSpectator}
                    gameStatus={gameStatus}
                    boardOrientation={boardOrientation}
                  />
                ) : (
                  <div className="flex flex-col items-center justify-center gap-4 py-20">
                    <div className="animate-spin">
                      <svg className="w-12 h-12 text-sky-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                      </svg>
                    </div>
                    <p className="text-slate-400">Waiting for pairing...</p>
                  </div>
                )}
              </div>
            </div>
          </div>

          {/* Sidebar */}
          <div>
            {/* Players Info */}
            <div className="card mb-6">
              <h3 className="text-lg font-bold mb-4">Players</h3>
              <div className="space-y-3">
                {room?.players?.map((p, idx) => (
                  <div key={idx} className="flex items-center gap-3 p-3 bg-slate-700/50 rounded-lg">
                    <div className="w-10 h-10 rounded-full bg-gradient-to-br from-sky-500 to-sky-600 flex items-center justify-center flex-shrink-0">
                      <span className="text-white font-bold text-sm">{p.username.charAt(0).toUpperCase()}</span>
                    </div>
                    <div className="flex-1">
                      <p className="text-white font-medium text-sm">{p.username}</p>
                      <p className="text-slate-400 text-xs">₹{p.wallet || 0}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Room Info */}
            <div className="card mb-6">
              <h3 className="text-lg font-bold mb-4">Room Info</h3>
              <div className="space-y-3 text-sm">
                <div className="flex justify-between">
                  <span className="text-slate-400">Entry Fee</span>
                  <span className="text-white font-semibold">₹{room?.entryFee || 0}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-slate-400">Prize Pool</span>
                  <span className="text-white font-semibold">₹{(room?.entryFee || 0) * (room?.players?.length || 0)}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-slate-400">Total Players</span>
                  <span className="text-white font-semibold">{room?.players?.length || 0}/{room?.maxPlayers || 0}</span>
                </div>
                <div className="border-t border-slate-700 pt-3 flex justify-between">
                  <span className="text-slate-400">Prize Type</span>
                  <span className="text-sky-400 font-semibold text-xs">
                    {room?.prizeDistribution === 'top4' ? 'Top 4' : 'Winner Takes All'}
                  </span>
                </div>
              </div>
            </div>

            {/* Status */}
            <div className={`card ${
              status.includes('ended') 
                ? 'bg-gradient-to-br from-green-900/30 to-green-800/30 border-green-700' 
                : 'bg-gradient-to-br from-blue-900/30 to-blue-800/30 border-blue-700'
            }`}>
              <h3 className="text-lg font-bold mb-3">Status</h3>
              <p className={`text-sm ${status.includes('ended') ? 'text-green-400' : 'text-blue-400'}`}>
                {status}
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
